7	describe('maskSensitiveData', () => {
8		describe('primitives and nullish values', () => {
9			it('should return null unchanged', () => {
10				expect(maskSensitiveData(null)).toBeNull();
11			});
12	
13			it('should return undefined unchanged', () => {
14				expect(maskSensitiveData(undefined)).toBeUndefined();
15			});
16	
17			it('should return a string unchanged', () => {
18				expect(maskSensitiveData('hello')).toBe('hello');
19			});
20	
21			it('should return a number unchanged', () => {
22				expect(maskSensitiveData(42)).toBe(42);
23			});
24	
25			it('should return a boolean unchanged', () => {
26				expect(maskSensitiveData(false)).toBe(false);
27			});
28		});
29	
30		describe('flat objects', () => {
31			it('should mask default sensitive key: password', () => {
32				const result = maskSensitiveData({
33					password: 'secret123',
34					name: 'Alice',
35				}) as Record<string, unknown>;
36				expect(result['password']).toBe('***MASKED***');
37				expect(result['name']).toBe('Alice');
